import { z } from 'zod';

export const E2E301ClientActionSchema = z.object({
  scenarioId: z.literal('e2e-301'),
  fixture: z.enum(['happy_path', 'idempotent_retry', 'downstream_failure', 'permission_denied']),
  action: z.enum(['start_flow', 'retry_same_request', 'simulate_failure', 'recover']),
  idempotencyKey: z.string().uuid(),
}).strict();

export const E2E301TrustedContextSchema = z.object({
  actorId: z.string().min(1),
  tenantId: z.string().min(1),
  role: z.enum(['owner','admin','member','viewer','system']),
  sessionId: z.string().min(1),
}).strict();

export const E2E301ResultSchema = z.object({
  status: z.enum(['passed','failed','denied','retryable_error']),
  httpStatus: z.union([z.literal(200), z.literal(202), z.literal(400), z.literal(403), z.literal(409), z.literal(422), z.literal(500)]),
  code: z.enum(['FLOW_COMPLETED', 'IDEMPOTENT_REPLAY', 'DOWNSTREAM_FAILED', 'PERMISSION_DENIED', 'RECOVERED']),
  userMessage: z.string().min(1),
  assertion: z.object({
    visibleState: z.literal('workflow_state_visible'),
    scenarioTitle: z.literal('Adding feature toggle with telemetry'),
    redactedTelemetry: z.object({ event: z.literal('e2e.e2e-301.checked'), category: z.literal('full_stack_verification'), redacted: z.literal(true) }),
  }),
}).strict();

backend_solution:
// e2e-301: typed route for Adding feature toggle with telemetry
export async function handleE2E301(req, ctx) {
  const input = E2E301Schema.parse(await req.json());
  const authz = await ctx.authz.assertCan(input.actorId, 'full_stack_verification', input.tenantId);
  const result = await ctx.db.transaction(tx => ctx.flows.adding_feature_toggle_with_telemet(tx, input, authz));
  ctx.metrics.observe('error_rate', result.metric);
  return Response.json(ResultSchema.parse(result));
}

